
.scene-bar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 16px;
  background: var(--c-card);
  border: 1px solid var(--c-card-border);
  border-radius: 8px;
  padding: 10px 14px;
  backdrop-filter: blur(8px);
}

.scene-item {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 12px;
  color: var(--c-text);

  &.muted {
    color: var(--c-text-muted);
    font-size: 11px;
  }
}

.icon {
  font-size: 13px;
  line-height: 1;
}
