
.phase-tag {
  margin-left: auto;
  font-size: 11px;
  font-weight: 500;
  color: var(--c-corruption);
  background: var(--c-corruption-glow);
  padding: 1px 8px;
  border-radius: 4px;
}

.bar-container {
  height: 8px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 4px;
  position: relative;
  margin-bottom: 6px;
}

.bar-fill {
  height: 100%;
  background: linear-gradient(90deg, #6d28d9, #8b5cf6, #a78bfa);
  border-radius: 4px;
  transition: width 0.6s ease;
  position: relative;
  z-index: 1;
}

.threshold-marker {
  position: absolute;
  top: -2px;
  width: 2px;
  height: 12px;
  background: rgba(255, 255, 255, 0.2);
  transform: translateX(-50%);
  z-index: 2;
}

.bar-labels {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
}

.bar-value {
  color: var(--c-corruption);
  font-weight: 500;
}

.bar-next {
  color: var(--c-text-muted);
}
