
.tag {
  margin-left: auto;
  font-size: 10px;
  color: var(--c-warning);
  background: rgba(245, 158, 11, 0.1);
  padding: 1px 6px;
  border-radius: 3px;
  text-transform: none;
  letter-spacing: 0;
}

.timeline {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.timeline-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  font-size: 12px;
  line-height: 1.5;
}

.timeline-dot {
  flex-shrink: 0;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--c-corruption);
  margin-top: 6px;
}

.timeline-text {
  color: var(--c-text);
  word-break: break-all;
}

.empty-state {
  text-align: center;
  color: var(--c-text-muted);
  font-size: 12px;
  padding: 8px 0;
}
