
.profile-grid {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.profile-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.profile-label {
  font-size: 11px;
  color: var(--c-text-muted);
}

.profile-value {
  font-size: 12px;
  color: var(--c-text);
  line-height: 1.5;
}

.suspicion .profile-value {
  color: var(--c-warning);
}
