
.dual-bars {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.bar-row {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.bar-label {
  display: flex;
  align-items: center;
  gap: 5px;
  font-size: 12px;
  color: var(--c-text);
}

.heart {
  color: var(--c-love);
  font-size: 14px;
}

.skull {
  color: var(--c-corruption);
  font-size: 14px;
}

.bar-value {
  margin-left: auto;
  font-weight: 600;
  font-size: 13px;
  color: var(--c-text);
}

.bar-track {
  height: 8px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 4px;
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.6s ease;
}

.bar-love {
  background: linear-gradient(90deg, #f472b6, #ff6b9d, #fb7185);
}

.bar-corruption {
  background: linear-gradient(90deg, #6d28d9, #8b5cf6, #a78bfa);
}

.gap-indicator {
  text-align: center;
  font-size: 11px;
  color: var(--c-text-muted);
  padding: 6px 0 2px;
  border-top: 1px solid var(--c-divider);
  margin-top: 4px;
  font-style: italic;
}
