
.toggle {
  margin-left: auto;
  font-size: 10px;
  color: var(--c-text-muted);
}

.secret-list {
  margin-top: 4px;
}

.list-items {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.list-item {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  font-size: 12px;
  color: var(--c-text);
  line-height: 1.5;
}

.lock {
  flex-shrink: 0;
  font-size: 11px;
  line-height: 1.5;
}

.empty-state {
  text-align: center;
  color: var(--c-text-muted);
  font-size: 12px;
  padding: 4px 0;
}
